#!/usr/bin/env python3 """ Check pipeline progress and generate summary """ from pathlib import Path import csv
ROOT_DIR = Path('/Users/taircarmon/Desktop/growth_function_posture_aware') OUTPUT_DIR = ROOT_DIR / 'analysis_full'
def check_progress(): print("="*70) print("PIPELINE PROGRESS CHECK") print("="*70)
if not OUTPUT_DIR.exists(): print("❌ analysis_full directory not found!") return
# Find all date folders date_folders = sorted([d for d in OUTPUT_DIR.iterdir() if d.is_dir() and d.name[0].isdigit()])
print(f"\n Date folders processed: {len(date_folders)}")
total_images = 0 total_larvae = 0
for date_folder in date_folders: image_folders = sorted([d for d in date_folder.iterdir() if d.is_dir()]) total_images += len(image_folders)
print(f"\n {date_folder.name}:") print(f" Images processed: {len(image_folders)}")
# Check first few images for i, img_folder in enumerate(image_folders[:3]): files = list(img_folder.iterdir()) csv_file = img_folder / 'morphometrics.csv'
if csv_file.exists(): with open(csv_file, 'r') as f: num_larvae = len(list(csv.DictReader(f))) total_larvae += num_larvae print(f" • {img_folder.name}: {num_larvae} larvae") else: print(f" • {img_folder.name}: No CSV found")
if len(image_folders) > 3: print(f" ... and {len(image_folders)-3} more images")
print(f"\n{'='*70}") print(f"TOTAL STATISTICS:") print(f" Total Images Processed: {total_images}") print(f" Total Larvae Detected: {total_larvae}") print("="*70)
# Check for global summary global_csv = OUTPUT_DIR / 'global_summary.csv' if global_csv.exists(): print(f"\n✅ Global summary exists: {global_csv}") with open(global_csv, 'r') as f: lines = len(f.readlines()) - 1 # Subtract header print(f" Contains {lines} image records") else: print(f"\n⚠️ Global summary not yet created")
if __name__ == "__main__": check_progress()

#!/usr/bin/env python3 """ Demo Script - Shows what the labeling tool will sample Runs without user interaction to preview the sampling plan """
import random from pathlib import Path from datetime import datetime
# Configuration (matches interactive_labeling_tool.py) ROOT_DIR = Path(__file__).parent / "analysis_full" IMAGES_PER_DATE = 3 LARVAE_PER_IMAGE = 8 RANDOM_SEED = 42
def demo_sampling(): print("="*70) print("LABELING TOOL - SAMPLING PREVIEW (DEMO MODE)") print("="*70) print(f"Configuration:") print(f" Images per date: {IMAGES_PER_DATE}") print(f" Larvae per image: {LARVAE_PER_IMAGE}") print(f" Random seed: {RANDOM_SEED}") print("="*70)
# Collect inventory print("\n Scanning analysis_full directory...\n")
larvae_inventory = {} date_folders = sorted([ d for d in ROOT_DIR.iterdir() if d.is_dir() and d.name[0].isdigit() ])
print(f"Found {len(date_folders)} date folders:") for df in date_folders: print(f" - {df.name}")
for date_folder in date_folders: date_name = date_folder.name larvae_inventory[date_name] = {}
image_folders = sorted([d for d in date_folder.iterdir() if d.is_dir()])
for image_folder in image_folders: larvae_reports_dir = image_folder / "larvae_reports" if larvae_reports_dir.exists(): larva_files = sorted([ f.name for f in larvae_reports_dir.iterdir() if f.name.startswith("larva_") and f.name.endswith(".png") ]) if larva_files: larvae_inventory[date_name][image_folder.name] = larva_files
# Statistics total_images = sum(len(images) for images in larvae_inventory.values()) total_larvae = sum( len(larvae) for images in larvae_inventory.values() for larvae in images.values() )
print(f"\n{'='*70}") print("INVENTORY SUMMARY") print(f"{'='*70}") print(f"Total Images: {total_images}") print(f"Total Larvae: {total_larvae}") print()
for date_name, images in sorted(larvae_inventory.items()): num_images = len(images) num_larvae = sum(len(larvae) for larvae in images.values()) print(f" {date_name}: {num_images:3d} images, {num_larvae:4d} larvae")
# Create sampling plan print(f"\n{'='*70}") print("SAMPLING PLAN (Random Seed = {})".format(RANDOM_SEED)) print(f"{'='*70}")
random.seed(RANDOM_SEED) sampling_plan = []
for date_name, images_dict in sorted(larvae_inventory.items()): if not images_dict: continue
available_images = list(images_dict.keys()) num_to_sample = min(IMAGES_PER_DATE, len(available_images)) selected_images = random.sample(available_images, num_to_sample)
print(f"\n {date_name}:") print(f" Sampling {num_to_sample} out of {len(available_images)} images")
for img_name in selected_images: larvae_files = images_dict[img_name] num_larvae_to_sample = min(LARVAE_PER_IMAGE, len(larvae_files)) selected_larvae = random.sample(larvae_files, num_larvae_to_sample)
print(f" {img_name}: {num_larvae_to_sample}/{len(larvae_files)} larvae")
for larva_file in selected_larvae: larva_path = ROOT_DIR / date_name / img_name / "larvae_reports" / larva_file sampling_plan.append((date_name, img_name, larva_file, larva_path))
print(f"\n{'='*70}") print("SAMPLING SUMMARY") print(f"{'='*70}") print(f"Total samples to label: {len(sampling_plan)}") print(f"Estimated time (30 sec/sample): {len(sampling_plan)*30/60:.1f} minutes") print("="*70)
# Show first 10 samples print("\n First 10 samples in queue:") for i, (date, img, larva, path) in enumerate(sampling_plan[:10], 1): exists = "✓" if path.exists() else "✗" print(f" {i:3d}. {date:6s} / {img:12s} / {larva:15s} {exists}")
if len(sampling_plan) > 10: print(f" ... and {len(sampling_plan)-10} more samples")
print(f"\n{'='*70}") print("To start actual labeling, run:") print(" python3 interactive_labeling_tool.py") print("="*70)
if __name__ == "__main__": demo_sampling()
